{
var seed = GetInt(parameters, "seed", context.Seed);
var cols = Math.Clamp(GetInt(parameters, "columns", 5), 3, 12);
var rows = Math.Clamp(GetInt(parameters, "rows", 5), 3, 12);
var irregularity = GetFloat(parameters, "irregularity", 0.4f);
var gapWidth = GetFloat(parameters, "gapWidth", 0.08f);
var roundness = GetFloat(parameters, "roundness", 0.3f);
var stoneColor = GetColor(parameters, "stoneColor", Color.FromRgb(160, 150, 140));
var gapColor = GetColor(parameters, "gapColor", Color.FromRgb(70, 65, 60));
var colorVar = GetFloat(parameters, "colorVariation", 0.15f);
var highlight = GetFloat(parameters, "highlight", 0.3f);
var shadow = GetFloat(parameters, "shadow", 0.25f);
var bumpDepth = GetFloat(parameters, "bumpDepth", 0.3f);
var edgeRoughness = GetFloat(parameters, "edgeRoughness", 0.2f);
var surfaceDetail = GetFloat(parameters, "surfaceDetail", 0.3f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var sR = stoneColor.R / 255f; var sG = stoneColor.G / 255f; var sB = stoneColor.B / 255f;
var gR = gapColor.R / 255f; var gG = gapColor.G / 255f; var gB = gapColor.B / 255f;

// Pre-generate stone centers with jitter
var cellW = 1f / cols;
var cellH = 1f / rows;
var maxJitterX = cellW * irregularity * 0.4f;
var maxJitterY = cellH * irregularity * 0.4f;

// Store jittered centers: [row, col] -> (cx, cy, hash)
var centers = new (float cx, float cy, float hash)[rows, cols];
for (var r = 0; r < rows; r++)
{
    for (var c = 0; c < cols; c++)
    {
        var baseCx = (c + 0.5f) * cellW;
        var baseCy = (r + 0.5f) * cellH;
        var jx = (HashToUnit(c * 13 + r * 7, seed, 111) - 0.5f) * 2f * maxJitterX;
        var jy = (HashToUnit(c * 7 + r * 13, seed + 50, 222) - 0.5f) * 2f * maxJitterY;
        var h = HashToUnit(c * 23 + r * 17, seed + 100, 333);
        centers[r, c] = (
            Math.Clamp(baseCx + jx, cellW * 0.1f, 1f - cellW * 0.1f),
            Math.Clamp(baseCy + jy, cellH * 0.1f, 1f - cellH * 0.1f),
            h
        );
    }
}

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Edge roughness perturbation
    var erU = u;
    var erV = v;
    if (edgeRoughness > 0f)
    {
        var erNoise = TileableFractalNoise(u * cols * 2f, v * rows * 2f,
            Math.Max(1, size / 2), 2, 0.5f, 2f, seed + 200);
        var erOffset = (erNoise - 0.5f) * edgeRoughness * cellW * 0.3f;
        erU += erOffset;
        erV += erOffset * 0.8f;
    }

    // Find nearest stone center (with wraparound for tiling)
    var minDistSq = float.MaxValue;
    var bestR = 0;
    var bestC = 0;
    var bestHash = 0f;
    var nearCenterX = 0f;
    var nearCenterY = 0f;

    // Check 3x3 neighborhood for wrap-around
    var baseRow = (int)MathF.Floor(erV / cellH);
    var baseCol = (int)MathF.Floor(erU / cellW);

    for (var dr = -1; dr <= 1; dr++)
    {
        for (var dc = -1; dc <= 1; dc++)
        {
            var nr = ((baseRow + dr) % rows + rows) % rows;
            var nc = ((baseCol + dc) % cols + cols) % cols;
            var (ccx, ccy, ch) = centers[nr, nc];

            // Wrapped distance
            var dx = erU - ccx;
            var dy = erV - ccy;
            if (dx > 0.5f) dx -= 1f; else if (dx < -0.5f) dx += 1f;
            if (dy > 0.5f) dy -= 1f; else if (dy < -0.5f) dy += 1f;

            var distSq = dx * dx + dy * dy;
            if (distSq < minDistSq)
            {
                minDistSq = distSq;
                bestR = nr;
                bestC = nc;
                bestHash = ch;
                nearCenterX = ccx;
                nearCenterY = ccy;
            }
        }
    }

    var dist = MathF.Sqrt(minDistSq);

    // Normalize distance relative to expected cell size
    var normCellSize = MathF.Sqrt(cellW * cellH) * 0.5f;
    var normDist = dist / normCellSize;

    // Distance to nearest edge of the stone (for gap and shading)
    var dxToCenter = erU - nearCenterX;
    var dyToCenter = erV - nearCenterY;
    if (dxToCenter > 0.5f) dxToCenter -= 1f; else if (dxToCenter < -0.5f) dxToCenter += 1f;
    if (dyToCenter > 0.5f) dyToCenter -= 1f; else if (dyToCenter < -0.5f) dyToCenter += 1f;

    // Elliptical distance scaled by cell aspect ratio
    var elDist = MathF.Sqrt(
        (dxToCenter / (cellW * 0.5f)) * (dxToCenter / (cellW * 0.5f)) +
        (dyToCenter / (cellH * 0.5f)) * (dyToCenter / (cellH * 0.5f))
    );

    // Apply roundness: blend between elliptical and Manhattan distance
    var circularDist = MathF.Sqrt(
        (dxToCenter * dxToCenter + dyToCenter * dyToCenter) / (0.5f * 0.5f));
    var effectiveDist = Lerp(elDist, circularDist, roundness);

    // Apply noise for organic stone shape
    if (irregularity > 0f)
    {
        var shapeNoise = TileableFractalNoise(
            u * cols * 1.5f + bestHash * 10f,
            v * rows * 1.5f + bestHash * 20f,
            Math.Max(1, size / 2), 2, 0.5f, 2f, seed + 300 + bestC * 7 + bestR * 13);
        effectiveDist += (shapeNoise - 0.5f) * irregularity * 0.3f;
    }

    // Gap + stone determination
    var gapThreshold = 1f - gapWidth * 2f;
    var isGap = effectiveDist > gapThreshold;

    float r, g, b;

    if (isGap)
    {
        // Mortar/gap: dark with slight variation
        var gapNoise = TileableFractalNoise(
            u * 5f + 100f, v * 5f + 100f,
            Math.Max(1, size / 2), 2, 0.5f, 2f, seed + 400);
        var gapVar = (gapNoise - 0.5f) * 0.1f;
        r = Math.Clamp(gR + gapVar, 0f, 1f);
        g = Math.Clamp(gG + gapVar * 0.9f, 0f, 1f);
        b = Math.Clamp(gB + gapVar * 0.8f, 0f, 1f);

        // Depth shading in gap (darker near stone edges)
        if (bumpDepth > 0f)
        {
            var depthFactor = (effectiveDist - gapThreshold) / (gapWidth * 2f);
            depthFactor = Math.Clamp(depthFactor, 0f, 1f);
            var depthDark = depthFactor * bumpDepth * 0.4f;
            r *= 1f - depthDark;
            g *= 1f - depthDark * 0.95f;
            b *= 1f - depthDark * 0.9f;
        }
    }
    else
    {
        // Stone surface
        var varAmt = (bestHash - 0.5f) * colorVar;
        r = Math.Clamp(sR + varAmt, 0f, 1f);
        g = Math.Clamp(sG + varAmt * 0.85f, 0f, 1f);
        b = Math.Clamp(sB + varAmt * 0.7f, 0f, 1f);

        // 3D edge shading: highlight on top-left, shadow on bottom-right
        var edgeT = 1f - effectiveDist / gapThreshold;
        edgeT = MathF.Max(0f, edgeT);

        // Light direction: top-left
        var lightDot = (-dxToCenter * 0.7f + -dyToCenter * 0.7f) / normCellSize;
        var hl = MathF.Max(0f, lightDot) * highlight * edgeT;
        var sh = MathF.Max(0f, -lightDot) * shadow * edgeT;

        r = Math.Clamp(r + hl - sh, 0f, 1f);
        g = Math.Clamp(g + hl * 0.85f - sh * 0.85f, 0f, 1f);
        b = Math.Clamp(b + hl * 0.7f - sh * 0.7f, 0f, 1f);

        // Surface detail noise
        if (surfaceDetail > 0f)
        {
            var detailNoise = TileableFractalNoise(
                u * cols * 4f, v * rows * 4f,
                Math.Max(1, size / 2), 2, 0.5f, 2.5f, seed + 500 + bestC * 11 + bestR * 17);
            var detail = (detailNoise - 0.5f) * surfaceDetail * 0.12f;
            r = Math.Clamp(r + detail, 0f, 1f);
            g = Math.Clamp(g + detail * 0.9f, 0f, 1f);
            b = Math.Clamp(b + detail * 0.8f, 0f, 1f);
        }

        // Subtle bump at stone center
        if (bumpDepth > 0f)
        {
            var centerBump = 1f - effectiveDist / gapThreshold;
            centerBump = MathF.Max(0f, centerBump);
            centerBump = centerBump * centerBump * bumpDepth * 0.08f;
            r = Math.Clamp(r + centerBump, 0f, 1f);
            g = Math.Clamp(g + centerBump * 0.9f, 0f, 1f);
            b = Math.Clamp(b + centerBump * 0.85f, 0f, 1f);
        }
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return buffer;
}
